var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......지나친 이미지 쇄신은 독이 된다는 사실을 이번 기회에 좀 느끼셨으면 좋겠네요.","JPN":"……イメージチェンジしすぎると良くないということを、これを機に覚えていただきたいですね。","ENG":"It's about time you learn that trying too hard to burnish your image can lead to negative results.","TWN":"……過度改變形象並不是件好事，希望您能藉這個機會認清這個事實。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 동안 누누이 말씀 드렸지만, 사장님께 필요한 건 건전한 소비습관과 규칙적인 외부 활동이에요.","JPN":"これまで何度も言いましたが、社長に必要なのは健全な消費習慣と規則的な外部活動です！","ENG":"As I told you a million times before, what you need to do is practice a wise spending habit, as well was regular external activities.","TWN":"這段時間我一直在和老闆說，老闆需要的，是健全的消費習慣和規律的戶外活動。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제가 관리하는 재무제표가 모범적인 성장세를 그리지 못하고 황금상 같은 부조리한 과소비에 꺾이다니!","JPN":"私が管理する財務諸表の実績が、お手本のような成長を描くことができず、黄金像のような無駄遣いのせいで挫かれるなんて！","ENG":"I can't stand the fact the company's financial stability, which I'm in sole charge of, dropped like that because of your stupid golden statue!","TWN":"我管理的財務報表居然沒有呈標準的成長曲線，竟然是因為黃金雕像這種不合理的過度消費！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"정말이지, 사장님이 아니라 독재자라고 부르는 편이 어울리겠어요.","JPN":"もう、社長じゃなくて独裁者と呼んだほうがお似合いです。","ENG":"We should start calling you tyrant rather than president.","TWN":"真是的。比起老闆，叫您獨裁者會比較合適吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"으흠 흠!","JPN":"こ、こほん！","ENG":"Well... I-I mean,","TWN":"咳咳！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"확실히 독재자란 표현은 좀 심하긴 했네요.","JPN":"確かに、独裁者という表現は言いすぎでした。","ENG":"Tyrant was too strong of a word.","TWN":"獨裁者這個說法確實有點過分了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"진심은 아니었으니 그런 표정 짓지 마세요.","JPN":"本意ではないので、そんな顔はしないでください。","ENG":"I didn't mean it. Please don't look at me like that.","TWN":"我不是認真的，請不要露出那個表情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......그래도 절 이렇게 부르신 걸 보면,","JPN":"……でも、こうして私を呼んだことから考えると、","ENG":"But given that you called me,","TWN":"不過，既然您把我叫來……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"앞으로 누구에게 일을 맡겨야 할지 정도는 깨달으신 것 같아서 다행이네요.","JPN":"これから誰に仕事を任せるべきかぐらいは、わかっているようでよかったです。","ENG":"I guess you finally figured out who's capable and who's not. I'm glad.","TWN":"就代表您曉得以後該把工作交付給誰，這真是太好了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"마침 지난 번에 주문했던 유용한 도서들이 도착한 참이거든요.","JPN":"ちょうど、先週注文した役に立ちそうな本が届いています。","ENG":"All the books I ordered for you a while ago have just arrived.","TWN":"正好，上次訂的書送來了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"기초적인 금융상식부터 회사운영까지, 델타 세븐 에이전트로서 자존심을 걸고 사장님을 쓸만한 경영진으로 만들어드리죠.","JPN":"基礎的な金融常識から会社経営まで、デルタセブンエージェントとして、プライドをかけて社長を立派な経営者にして見せます。","ENG":"I'll teach you everything from basic finance to running a company. I'll turn you into a capable member of the board, with my pride as a Delta Seven agent on the line.","TWN":"從基礎金融知識到公司營運，賭上第七三角洲部隊代理人的驕傲，我一定會為老闆打造一支優秀的經營團隊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네? 도서목록 중에 수상한 이름이...... 껴있다고요?","JPN":"はい？書籍一覧の中に怪しいタイトルが……挟まっていると？","ENG":"Sorry? There's a strange book among the books that arrived?","TWN":"咦？您說目錄裡……有個奇怪的書名混在裡面？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"연애도서라뇨. 배송에 착오가 있었을 겁니다. 이리 주세요.","JPN":"恋愛本だなんて。配送に間違いがあったようです。こちらに渡してください。","ENG":"A romance novel? It must have been a mistake or something. Give it to me.","TWN":"竟然是戀愛小說。一定是送錯了，請快給我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제, 제목 읽지 마시라고요!","JPN":"た、タイトルは読まないでください！","ENG":"D-don't read the title out loud!","TWN":"請、請不要把書名念出來！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};